if (!function_exists('get_setting_lang')) {
  function get_setting_lang($baseKey, $default='') {
    if (is_en()) {
      $v = get_setting($baseKey . '_en', '');
      if ($v !== '') return $v;
    }

    return get_setting($baseKey, $default);
  }
}